import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
const TEST_HOME = path.join(os.tmpdir(), `bitfab-active-preview-test-${process.pid}`);
vi.mock("node:os", async (importOriginal) => {
    const actual = await importOriginal();
    return {
        ...actual,
        homedir: () => TEST_HOME,
        default: { ...actual, homedir: () => TEST_HOME },
    };
});
const FILE_PATH = path.join(TEST_HOME, ".config", "bitfab", "active-preview-session.json");
// Import after the mock so the module's top-level path resolution sees the
// test homedir.
const { writeActivePreviewSession, clearActivePreviewSession, readActivePreviewSession, } = await import("./activePreviewSession.js");
describe("activePreviewSession", () => {
    beforeEach(() => {
        fs.rmSync(TEST_HOME, { recursive: true, force: true });
    });
    afterEach(() => {
        fs.rmSync(TEST_HOME, { recursive: true, force: true });
    });
    it("writes and reads back the active session", () => {
        writeActivePreviewSession({
            sessionId: "test-session-id",
            serviceUrl: "http://localhost:3001",
        });
        const got = readActivePreviewSession();
        expect(got).not.toBeNull();
        expect(got?.sessionId).toBe("test-session-id");
        expect(got?.serviceUrl).toBe("http://localhost:3001");
        expect(got?.pid).toBe(process.pid);
        expect(typeof got?.startedAt).toBe("string");
    });
    it("returns null when no session has been written", () => {
        expect(readActivePreviewSession()).toBeNull();
    });
    it("treats a session recorded by a dead pid as stale", () => {
        fs.mkdirSync(path.dirname(FILE_PATH), { recursive: true });
        // Pick a pid that almost certainly does not correspond to a real
        // process. Linux MAX_PID is 4194304; pick something well past it.
        const deadPid = 9_999_999;
        fs.writeFileSync(FILE_PATH, JSON.stringify({
            sessionId: "stale",
            serviceUrl: "http://localhost",
            pid: deadPid,
            startedAt: new Date().toISOString(),
        }));
        expect(readActivePreviewSession()).toBeNull();
    });
    it("returns null when the file is malformed", () => {
        fs.mkdirSync(path.dirname(FILE_PATH), { recursive: true });
        fs.writeFileSync(FILE_PATH, "not json");
        expect(readActivePreviewSession()).toBeNull();
    });
    it("clearActivePreviewSession removes the file when pid matches", () => {
        writeActivePreviewSession({
            sessionId: "to-clear",
            serviceUrl: "http://localhost",
        });
        expect(readActivePreviewSession()).not.toBeNull();
        clearActivePreviewSession();
        expect(fs.existsSync(FILE_PATH)).toBe(false);
    });
    it("clearActivePreviewSession leaves a foreign-pid file alone", () => {
        fs.mkdirSync(path.dirname(FILE_PATH), { recursive: true });
        fs.writeFileSync(FILE_PATH, JSON.stringify({
            sessionId: "foreign",
            serviceUrl: "http://localhost",
            pid: process.pid + 1,
            startedAt: new Date().toISOString(),
        }));
        clearActivePreviewSession();
        expect(fs.existsSync(FILE_PATH)).toBe(true);
    });
});
